# Production-grade retrieval evaluation at scale
import numpy as np
from typing import List, Dict

class ProductionRetrieval:
    def __init__(self, k_thresholds: List[int] = [1, 5, 10, 20]):
        self.k_thresholds = k_thresholds
        self.metrics_history = []

    def evaluate_batch(self, queries: List[Dict]) -> Dict:
        """Evaluate retrieval on batch of cricket queries"""
        results = {}

        for k in self.k_thresholds:
            precision_at_k = self._calculate_precision_at_k(
                queries, k
            )
            recall_at_k = self._calculate_recall_at_k(
                queries, k
            )
            ndcg_at_k = self._calculate_ndcg_at_k(
                queries, k
            )

            results[f'p@{k}'] = precision_at_k
            results[f'r@{k}'] = recall_at_k
            results[f'ndcg@{k}'] = ndcg_at_k

        # Track for monitoring
        self.metrics_history.append(results)
        return results

    def _calculate_precision_at_k(self, queries, k):
        """Precision: relevant batsmen in top-k retrieved"""
        precisions = []
        for query in queries:
            relevant_count = sum(
                1 for r in query['retrieved'][:k] 
                if r['is_relevant']
            )
            precisions.append(relevant_count / min(k, len(
                query['retrieved']
            )))
        return np.mean(precisions)

    def _calculate_recall_at_k(self, queries, k):
        """Recall: fraction of all relevant batsmen retrieved"""
        recalls = []
        for query in queries:
            if query['total_relevant'] == 0:
                recalls.append(1.0)
                continue
            relevant_in_top_k = sum(
                1 for r in query['retrieved'][:k] 
                if r['is_relevant']
            )
            recalls.append(
                relevant_in_top_k / query['total_relevant']
            )
        return np.mean(recalls)

    def _calculate_ndcg_at_k(self, queries, k):
        """NDCG: discounted value of relevance ranking"""
        ndcgs = []
        for query in queries:
            dcg = sum(
                query['retrieved'][i]['relevance_score'] / 
                np.log2(i + 2)
                for i in range(min(k, len(
                    query['retrieved']
                )))
            )

            # Ideal DCG: all relevant items ranked first
            idcg = sum(
                1.0 / np.log2(i + 2) 
                for i in range(
                    min(k, query['total_relevant'])
                )
            )

            ndcgs.append(dcg / idcg if idcg > 0 else 0)

        return np.mean(ndcgs)

    def detect_degradation(self, threshold: float = 0.02):
        """Alert if NDCG@10 drops >2% in recent batch"""
        if len(self.metrics_history) < 2:
            return None

        prev_ndcg = self.metrics_history[-2].get('ndcg@10')
        curr_ndcg = self.metrics_history[-1].get('ndcg@10')

        if prev_ndcg and curr_ndcg:
            drop = (prev_ndcg - curr_ndcg) / prev_ndcg
            if drop > threshold:
                return {
                    'alert': True,
                    'metric': 'ndcg@10',
                    'drop_percentage': drop * 100,
                    'action': 'Rollback or investigate retrieval'
                }
        return None

# Example: Evaluating cricket player retrieval
queries = [
    {
        'query': 'best batsmen 2024',
        'total_relevant': 5,
        'retrieved': [
            {'name': 'Virat Kohli', 'relevance_score': 1.0, 
             'is_relevant': True},
            {'name': 'Joe Root', 'relevance_score': 0.95, 
             'is_relevant': True},
            {'name': 'Player X', 'relevance_score': 0.1, 
             'is_relevant': False},
            {'name': 'Babar Azam', 'relevance_score': 0.92, 
             'is_relevant': True},
            {'name': 'Steve Smith', 'relevance_score': 0.88, 
             'is_relevant': True},
        ]
    }
]

retrieval = ProductionRetrieval()
metrics = retrieval.evaluate_batch(queries)
print('Metrics:', metrics)
